#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e5+5;
struct query{LL l,r,id;}q[N];
LL n,X,sq,a[N],m,L=1,R=0,c[N];
LL nowAns,ans[N];map<LL,LL> Ls;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(query q1,query q2){
    if(q1.l/sq!=q2.l/sq)return q1.l<q2.l;
    if((q1.l/sq)&1)return q1.r<q2.r;else return q1.r>q2.r;
}
void Add(LL p){
    nowAns-=c[a[p]]*c[a[p]];c[a[p]]++;
    nowAns+=c[a[p]]*c[a[p]];return;
}
void Del(LL p){
    nowAns-=c[a[p]]*c[a[p]];c[a[p]]--;
    nowAns+=c[a[p]]*c[a[p]];return;
}
int main(){
    n=read(),m=read(),X=read();
    sq=sqrt(n);
    for(LL i=1;i<=n;i++)a[i]=read();
    for(LL i=1;i<=m;i++)
        q[i].l=read(),q[i].r=read(),q[i].id=i;
    sort(q+1,q+m+1,cmp);
    for(LL i=1;i<=m;i++){
        while(L>q[i].l)Add(--L);
        while(R<q[i].r)Add(++R);
        while(L<q[i].l)Del(L++);
        while(R>q[i].r)Del(R--);
        ans[q[i].id]=nowAns;
    }for(LL i=1;i<=m;i++)cout<<ans[i]<<"\n";
    return 0;
}
